# Manually fixed: parameter naming and ordering
"""
TDD Stage: full_layer_norm
Complete layer normalization: tilize, mean, center, variance, rsqrt, normalize, apply gamma and beta, untilize
"""

import pytest
import torch
import ttnn


from .layer_norm_rm import layer_norm_rm


def pytorch_reference(input_tensor, gamma, beta):
    """PyTorch reference for this stage."""
    x = input_tensor.float()
    W = x.shape[-1]
    result = torch.nn.functional.layer_norm(
        x, [W], weight=gamma.squeeze().float(), bias=beta.squeeze().float(), eps=1e-5
    )
    return result.to(torch.bfloat16)


@pytest.mark.parametrize(
    "shape",
    [
        pytest.param((1, 1, 32, 32), id="1x1x32x32"),
        pytest.param((1, 1, 32, 64), id="1x1x32x64"),
        pytest.param((1, 1, 64, 128), id="1x1x64x128"),
        pytest.param((1, 1, 32, 256), id="1x1x32x256"),
        pytest.param((2, 1, 64, 64), id="2x1x64x64"),
    ],
)
def test_full_layer_norm(device, shape):
    """Verify complete layer normalization with gamma and beta."""
    torch.manual_seed(42)
    torch_input = torch.randn(shape, dtype=torch.bfloat16)
    gamma = torch.randn(1, 1, 1, shape[-1], dtype=torch.bfloat16)
    beta = torch.randn(1, 1, 1, shape[-1], dtype=torch.bfloat16)

    expected = pytorch_reference(torch_input, gamma, beta)

    ttnn_input = ttnn.from_torch(
        torch_input,
        dtype=ttnn.bfloat16,
        layout=ttnn.ROW_MAJOR_LAYOUT,
        device=device,
        memory_config=ttnn.DRAM_MEMORY_CONFIG,
    )
    ttnn_gamma = ttnn.from_torch(
        gamma,
        dtype=ttnn.bfloat16,
        layout=ttnn.ROW_MAJOR_LAYOUT,
        device=device,
        memory_config=ttnn.DRAM_MEMORY_CONFIG,
    )
    ttnn_beta = ttnn.from_torch(
        beta,
        dtype=ttnn.bfloat16,
        layout=ttnn.ROW_MAJOR_LAYOUT,
        device=device,
        memory_config=ttnn.DRAM_MEMORY_CONFIG,
    )

    ttnn_output = layer_norm_rm(ttnn_input, ttnn_gamma, ttnn_beta)

    # Shape check
    expected_shape = list(shape)
    assert list(ttnn_output.shape) == expected_shape, f"Shape: {list(ttnn_output.shape)} vs expected {expected_shape}"

    # Numerical comparison
    torch_output = ttnn.to_torch(ttnn_output)
    assert torch.allclose(
        torch_output.float(),
        expected.float(),
        rtol=0.05,
        atol=0.2,
    ), f"Max diff: {(torch_output.float() - expected.float()).abs().max()}"
